{
  "name": "User Processing Pipeline",
  "nodes": [
    {
      "name": "When clicking 'Execute workflow'",
      "type": "n8n-nodes-base.manualTrigger",
      "position": [0, 0]
    },
    {
      "name": "Create Sample Users",
      "type": "n8n-nodes-base.set",
      "position": [220, 0],
      "parameters": {
        "assignments": {
          "assignments": [
            {
              "name": "users",
              "value": "={{ [{\"name\": \"Alice\", \"email\": \"alice@test.com\", \"role\": \"admin\"}, {\"name\": \"Bob\", \"email\": \"bob@test.com\", \"role\": \"user\"}] }}",
              "type": "array"
            }
          ]
        }
      }
    },
    {
      "name": "Split Into Items",
      "type": "n8n-nodes-base.splitOut",
      "position": [440, 0],
      "parameters": {
        "fieldToSplitOut": "users"
      }
    },
    {
      "name": "Transform Data",
      "type": "n8n-nodes-base.set",
      "position": [660, 0],
      "parameters": {
        "assignments": {
          "assignments": [
            {
              "name": "emailDomain",
              "value": "={{ $json.email.split('@')[1] }}",
              "type": "string"
            },
            {
              "name": "displayName",
              "value": "={{ $json.name }} ({{ $json.role }})",
              "type": "string"
            },
            {
              "name": "welcomeMessage",
              "value": "={{ 'Welcome ' + $json.name + '! Your email is ' + $json.email }}",
              "type": "string"
            }
          ]
        }
      }
    }
  ],
  "connections": {
    "When clicking 'Execute workflow'": {
      "main": [[{"node": "Create Sample Users"}]]
    },
    "Create Sample Users": {
      "main": [[{"node": "Split Into Items"}]]
    },
    "Split Into Items": {
      "main": [[{"node": "Transform Data"}]]
    }
  }
}

